from typing import Any, Optional
import numpy as np
from leann.api import compute_embeddings
from functools import lru_cache

# Global cache
_cached_compute_memo = {}


def _cached_compute(cache_key: tuple, provider_options: Optional[dict[str, Any]]):
    texts_tuple, model_name, mode, options_set = cache_key
    texts_list = list(texts_tuple)
    embedding_opts = dict(options_set) if options_set else provider_options
    embeddings = compute_embeddings(
        chunks=texts_list,
        model_name=model_name,
        mode=mode,
        use_server=False,
        is_build=False,
        provider_options=embedding_opts,
    )
    return np.asarray(embeddings)


def _get_cached_result(key, compute_func):
    if key in _cached_compute_memo:
        return _cached_compute_memo[key]
    result = compute_func()
    _cached_compute_memo[key] = result
    return result


def compute_embeddings_with_config(
    texts: list[str],
    model_name: str = "facebook/contriever",
    mode: str = "sentence-transformers",
    embedding_options: Optional[dict[str, Any]] = None,
    use_cache: bool = False,
) -> np.ndarray:
    if not texts:
        raise ValueError("texts cannot be empty")
    valid_modes = {"sentence-transformers", "mlx", "openai", "ollama"}
    if mode not in valid_modes:
        raise ValueError(f"mode must be one of {valid_modes}")

    embedding_options = embedding_options or {}
    provider_options = embedding_options.get("provider_options", None)

    texts_tuple = tuple(texts)
    options_set = frozenset(embedding_options.items()) if embedding_options else None
    cache_key = (texts_tuple, model_name, mode, options_set)

    def compute():
        return _cached_compute(cache_key, provider_options=provider_options)

    if use_cache:
        return _get_cached_result(cache_key, compute)
    else:
        return compute()

