def search_with_metadata_filtering(
    index_path: str,
    query: str,
    metadata_filters: dict[str, dict[str, Any]],
    top_k: int = 5,
) -> list[SearchResult]:
    """
    Search in a LEANN index with metadata filters.

    Args:
        index_path: Path to LEANN index file
        query: Text query to search for
        metadata_filters: Filters to apply to metadata. Format: {"field": {"operator": value}}
        top_k: Number of nearest neighbors to return

    Returns:
        List of SearchResult objects matching both query and metadata filters
    """
    # Check if index file exists
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    # Initialize searcher and perform search
    searcher = LeannSearcher(index_path)
    results = searcher.search(query, top_k=top_k)

    # Apply metadata filters
    filtered: list[SearchResult] = []
    for result in results:
        passes = True
        for field, condition in metadata_filters.items():
            operator = condition["operator"]
            expected = condition["value"]
            actual = result.metadata.get(field)

            if actual is None:
                passes = False
                break

            # Type coercion for numeric comparisons
            try:
                if isinstance(actual, str) and isinstance(expected, (int, float)):
                    actual = type(expected)(actual)
                elif isinstance(expected, str) and isinstance(actual, (int, float)):
                    expected = type(actual)(expected)
            except (ValueError, TypeError):
                # Keep original types if coercion fails
                pass

            # Evaluate condition
            if operator == "==":
                if actual != expected:
                    passes = False
                    break
            elif operator == "!=":
                if actual == expected:
                    passes = False
                    break
            elif operator == "<":
                if not isinstance(actual, (int, float)) or not isinstance(expected, (int, float)):
                    raise ValueError("Comparison operators '<' require numeric types")
                if actual >= expected:
                    passes = False
                    break
            elif operator == "<=":
                if not isinstance(actual, (int, float)) or not isinstance(expected, (int, float)):
                    raise ValueError("Comparison operators '<=' require numeric types")
                if actual > expected:
                    passes = False
                    break
            elif operator == ">":
                if not isinstance(actual, (int, float)) or not isinstance(expected, (int, float)):
                    raise ValueError("Comparison operators '>' require numeric types")
                if actual <= expected:
                    passes = False
                    break
            elif operator == ">=":
                if not isinstance(actual, (int, float)) or not isinstance(expected, (int, float)):
                    raise ValueError("Comparison operators '>=' require numeric types")
                if actual < expected:
                    passes = False
                    break
            else:
                raise ValueError(f"Invalid operator: {operator}")

        if passes:
            filtered.append(result)

    return filtered[:top_k]

