def get_index_statistics(index_path: str) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError("Index metadata file not found")

    with open(meta_path) as f:
        meta = json.load(f)
    total_passages = meta.get('total_passages', 0)

    pm = PassageManager(index_path=index_path)
    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for passage in pm.passages:
        for field, value in passage.meta.items():
            metadata_fields.add(field)
            field_value_counts[field][value] += 1

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(metadata_fields),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError("Index metadata file not found")

    with open(meta_path) as f:
        meta = json.load(f)
    total_passages = meta.get('total_passages', 0)

    if total_passages == 0:
        return {
            "coverage_percentage": 100.0 if not required_fields else 0.0,
            "field_coverage": {field: 100.0 for field in required_fields},
            "missing_fields": []
        }

    pm = PassageManager(index_path=index_path)
    total_covered = 0
    field_counts = defaultdict(int)
    missing_fields = set(required_fields)

    for passage in pm.passages:
        has_all = True
        for field in required_fields:
            if field not in passage.meta:
                has_all = False
                break
        if has_all:
            total_covered += 1
        for field in required_fields:
            if field in passage.meta:
                field_counts[field] += 1
        # Update missing fields
        present = set(passage.meta.keys())
        missing_fields.difference_update(present)

    coverage_percentage = (total_covered / total_passages) * 100
    field_coverage = {field: (count / total_passages) * 100 for field, count in field_counts.items()}

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": sorted(missing_fields)
    }

