import os

def search_with_recency_boost(
    index_path: str,
    query: str,
    date_field: str,
    recency_days: int = 30,
    top_k: int = 10
) -> List[SearchResult]:
    if not os.path.exists(index_path):
        raise FileNotFoundError("Index file not found")
    if recency_days <= 0:
        raise ValueError("recency_days must be greater than 0")

    searcher = LeannSearcher(index_path)
    raw_results = searcher.search(query)
    now = datetime.now()
    adjusted = []

    for res in raw_results:
        date_str = res.metadata.get(date_field)
        if not date_str:
            adjusted_score = res.score
        else:
            try:
                date = datetime.fromisoformat(date_str)
            except ValueError:
                # Try to parse as timestamp (seconds or milliseconds)
                try:
                    if '.' in date_str:
                        date = datetime.fromtimestamp(float(date_str) / 1000)
                    else:
                        date = datetime.fromtimestamp(int(date_str))
                except (ValueError, TypeError):
                    adjusted_score = res.score
                    continue  # Skip this result if date parsing fails

            if date > now:
                recency_score = 0
            else:
                days_diff = (now - date).days
                if days_diff > recency_days:
                    recency_score = 0
                else:
                    recency_score = recency_days - days_diff
            adjusted_score = res.score + recency_score

        adjusted.append(
            SearchResult(
                id=res.id,
                score=adjusted_score,
                text=res.text,
                metadata=res.metadata
            )
        )

    sorted_results = sorted(adjusted, key=lambda x: x.score, reverse=True)
    return sorted_results[:top_k]

