def build_index_from_text_file(
    text_file_path: str,
    index_path: str,
    metadata: Optional[dict[str, Any]] = None,
    backend_name: str = "hnsw"
) -> str:
    if not Path(text_file_path).exists():
        raise FileNotFoundError(f"Text file not found: {text_file_path}")

    # Check if file is empty
    try:
        with open(text_file_path, 'rb') as f:
            if len(f.read()) == 0:
                raise ValueError("Text file is empty")
    except Exception:
        raise ValueError("Text file is empty")

    with open(text_file_path, encoding='utf-8') as f:
        lines = f.readlines()
    filtered_lines = [line.strip() for line in lines if line.strip()]
    if not filtered_lines:
        raise ValueError("Text file is empty or contains only empty lines")

    passages = []
    for i, line in enumerate(filtered_lines):
        text = line.strip()
        passage = {
            'id': str(i),
            'text': text,
            'metadata': metadata or {}
        }
        passages.append(passage)

    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build_index(passages, index_path=index_path)

    return index_path

